$(window).ready(function () {
    awardSlider = tns({
        container: ".award-slider",
        items: 1,
        autoHeight: true,
        autoplay: !1,
        autoplayTimeout: 5e3,
        autoplayButtonOutput: !1,
        controls: !1,
        loop: !0,
        nav: !1,
        responsive: {
            768: {
                items: 2
            }
        }
    });

    $(".award-prev").on("click", function () {
        awardSlider.goTo("prev")
    }), $(".award-next").on("click", function () {
        awardSlider.goTo("next")
    });

    slider = tns({
        container: ".my-slider",
        items: 1,
        autoHeight: true,
        autoplay: !1,
        autoplayTimeout: 5e3,
        autoplayButtonOutput: !1,
        controlsContainer: "#controls",
        prevButton: ".prev",
        nextButton: ".next",
        nav: !1
    });

    $(function () {
        let t = $(".tns-outer"),
            n = $(".client-toggle");
        t.addClass("max-h-80 overflow-y-clip md:max-h-max"), n.on("click", function () {
            let n = t.hasClass("max-h-max");
            t.toggleClass("max-h-80 max-h-max"), $(this).text(n ? "Show More" : "Show Less")
        })
    });

    const sectorMap = ["BUMN & BUMD", "Energy & Mining", "Finance & Banking", "Manufacturing & Construction", "Government", "Telecommunications, Transportation & Entertainment"];

    function updateClientSector(t) {
        t -= 1, $(".client-sector").text(sectorMap[t])
    }
    updateClientSector(slider.getInfo().index), slider.events.on("indexChanged", function (t) {
        updateClientSector(t.index)
    });
})
